def get_subjects() -> Tuple:
    subjects: list[str] = []
    ids: list[str] = []
    pages_csv = Path(__file__).resolve().parent / "pages.csv"
    with pages_csv.open(newline="") as csvfile:
        spamreader = csv.reader(csvfile)
        for row in spamreader:
            for i, subject in enumerate(row, start=1):
                ids.append(str(i))
                subjects.append(subject)
    return subjects, ids


def get_paragraphs() -> list[str]:
    soup = BeautifulSoup(res["parse"]["text"]["*"], "html.parser")
    title = res["parse"]["title"]
    container = soup.select_one(".mw-parser-output")
    if not container:
        container = soup
    chunks = []
    facts = get_info(container)
    if facts:
        chunks.append(f"{title}|Facts {facts}")
    heading = ["Overview"]
    for node in container.children:
        if not isinstance(node, Tag):
            continue
        if node.name == "h2":
            new_heading = get_heading(node)
            if new_heading:
                heading = [new_heading]
            else:
                raise Exception("heading not found")
        if node.name == "h3":
            new_sub_heading = get_heading(node)
            if not new_sub_heading:
                continue
            if len(heading) > 1:
                heading.pop()
            heading.append(new_sub_heading)
        # paragraph parsing ignoring schedule text
        elif node.name == "p":
            if "Schedule" in heading or "Gifts" in heading:
                continue
            text = node.get_text(" ", strip=True)
            if text:
                chunks.append(
                    f"{title}|{"|".join(heading)} {text}",
                )

        # table parsing
        elif node.name == "table":
            content = None
            classes = node.get("class", [])
            if "Schedule" in heading:
                content = parse_schedule(node)
            elif "wikitable" in classes or "mw-collapsible" in classes:
                content = parse_table(node)
            if content:
                chunks.append(f"{title}|{"|".join(heading)} {content}")
    return chunks


def get_heading(el: Tag) -> str | None:
    text = el.select_one("span.mw-headline")
    if text:
        return text.get_text(strip=True)


def parse_table(el: Tag) -> str | None:
    body = el.select_one("tbody")
    headers = "|".join([th.get_text(strip=True) for th in body.find_all("th")])
    rows = []
    for row in body.select("tr:not(:has(th))"):
        rows.append(row.get_text(" ", strip=True))
    if rows:
        return f"{headers} {" ".join(rows)}"


def parse_schedule(el: Tag) -> str:
    body = el.select_one("tbody")
    title = body.select_one("tr th").get_text(strip=True)
    content = body.select_one("tr td")
    sub_title = None
    sub_table_content = []
    for node in content.children:
        if node.name == "p":
            sub_title = node.get_text(strip=True)
            continue
        if node.name == "table":
            table = node.select_one("tbody")
            content = []
            if table is None:
                return
            for row in table.select("tr:not(:has(th))"):
                text = row.get_text(" ", strip=True)
                content.append(text)
            if content:
                sub_table_content.append(f"|{sub_title}|{"".join(content)}")
    return f"|{title} {" ".join(sub_table_content)}"


def get_info(soup: BeautifulSoup) -> str:
    infobox = soup.select_one("table#infoboxtable")
    if not infobox:
        None
    facts = ""
    for row in infobox.select("tr"):
        section = row.select_one("td#infoboxsection")
        detail = row.select_one("td#infoboxdetail")
        if section and detail:
            key = section.get_text(strip=True)
            value = get_detail(detail)
            facts += f"{key}:{value}. "
    return facts


def get_detail(detail: Tag) -> str:
    nametemplate_spans = detail.select("span.nametemplate")
    if nametemplate_spans:
        return ", ".join([s.find("a").get_text(strip=True) for s in nametemplate_spans])

    paragraphs = detail.select("p")
    if paragraphs:
        return ", ".join([p.get_text(separator=" ", strip=True) for p in paragraphs])

    return detail.get_text(separator=" ", strip=True)


async def test_article():
    chroma_client = chromadb.PersistentClient(path="./db")
    collection = chroma_client.get_or_create_collection(name="articles", embedding_function=sentence_transformer_ef)
    documents = get_paragraphs()
    ids = [f"alex-{i}" for i in range(len(documents))]
    collection.add(documents=documents, ids=ids)


